from qiskit import QuantumCircuit
from typing import Dict, List

class DepthAnalyzer:
    """Analyze quantum circuit depth."""

    def __init__(self, circuit: QuantumCircuit):
        self.circuit = circuit
        self.qubit_depths = {}
        self._analyze()

    def _analyze(self):
        """Compute depth per qubit."""
        depths = {i: 0 for i in range(self.circuit.num_qubits)}

        for instruction in self.circuit.data:
            if instruction.operation.name in ['barrier', 'measure']:
                continue

            # Get qubit indices
            qubits = [self.circuit.find_bit(q).index for q in instruction.qubits]

            # All qubits sync to max current depth, then increment
            max_depth = max(depths[q] for q in qubits)
            for q in qubits:
                depths[q] = max_depth + 1

        self.qubit_depths = depths

    def get_total_depth(self) -> int:
        """Get total circuit depth."""
        return max(self.qubit_depths.values()) if self.qubit_depths else 0

    def get_critical_qubits(self) -> List[int]:
        """Get qubits on critical path."""
        max_depth = self.get_total_depth()
        return [q for q, d in self.qubit_depths.items() if d == max_depth]

    def get_gate_depth_contribution(self) -> Dict[str, int]:
        """Get count per gate type."""
        contribution = {}
        for instruction in self.circuit.data:
            name = instruction.operation.name
            if name not in ['barrier', 'measure']:
                contribution[name] = contribution.get(name, 0) + 1
        return contribution

# Test
qc = QuantumCircuit(3)
qc.h(0)
qc.cx(0, 1)
qc.h(2)  # Parallel with cx
qc.cx(1, 2)

analyzer = DepthAnalyzer(qc)
print(f"Total depth: {analyzer.get_total_depth()}")
print(f"Critical qubits: {analyzer.get_critical_qubits()}")
print(f"Per-qubit depths: {analyzer.qubit_depths}")

